75	    fn name(&self) -> &str {
76	        "zcr-with-2t: zc-ring-x1 reserve_slot_with round-trip (2 threads, spin)"
77	    }
78	
79	    fn step(&mut self) -> u64 {
80	        self.counter = self.counter.wrapping_add(1);
81	        if self.counter == STOP {
82	            self.counter = 1;
83	        }
84	        let mut slot = self
85	            .req_tx
86	            .reserve_slot_with::<Msg>(|_| {
87	                core::hint::spin_loop();
88	                true
89	            })
90	            .expect("spin closure never gives up");
91	        *slot = self.counter;
92	        slot.commit();
93	        let slot = self
94	            .resp_rx
95	            .reserve_slot_with::<Msg>(|_| {
96	                core::hint::spin_loop();
97	                true
98	            })
99	            .expect("spin closure never gives up");
