41	// the shared state (producer_idx, seqs) is atomic, slot claims
42	// are exclusive by CAS, and slot writes are handed off with
43	// Release/Acquire ordering.
44	unsafe impl Send for MpscProducer<'_> {}
45	// SAFETY: send_with is &self and every access is protected as
46	// above, so shared references across threads are equally fine.
47	unsafe impl Sync for MpscProducer<'_> {}
