//! TProbe-decomposed variant of [`zcr_with_2t`][super::zcr_with_2t]:
//! the same SPSC round-trip with each of the four protocol phases
//! measured by its own [`TProbe`].
//!
//! Phases (main thread: `send req` / `recv resp`; worker: `recv
//! req` / `send resp`) bracket the endpoint call with two
//! [`crate::ticks::read_ticks`] reads, so each histogram isolates
//! one side of the handoff:
//!
//! - `send` phases capture the producer's reserve + fill + commit
//!   — including any stall acquiring peer-written cache lines.
//! - `recv` phases capture the consumer's spin wait + read +
//!   release, so they absorb the in-flight half-trip (the worker's
//!   `recv req` also absorbs main's inter-iteration framing).
//!
//! Run back-to-back with [`tp_zcr_mpsc_2t`][super::tp_zcr_mpsc_2t]
//! to localize the SPSC-vs-MPSC 2t gap (zc-ring-x1 Todo: explore
//! why zcr-mpsc-2t measures faster than zcr-with-2t).
//!
//! Per-phase probing adds ~4 tick-read pairs + histogram records
//! per round trip, so the harness-level mean is inflated vs the
//! unprobed bench; the phase histograms themselves stay tight
//! (each pair brackets only its endpoint call).

use std::hint::black_box;
use std::thread;

use zc_ring_x1::{Consumer, Producer};

use crate::benches::zcr_common::{Msg, STOP, leak_ring};
use crate::harness::{self, Bench, RunCfg};
use crate::pin;
use crate::ticks;
use crate::tprobe::TProbe;

/// Registry name used on the CLI.
pub const NAME: &str = "tp-zcr-with-2t";

/// Probed variant of `zcr-with-2t`. Main-thread probes live in
/// the struct; the worker's travel back on shutdown via
/// `JoinHandle<(TProbe, TProbe)>`. Call [`finish`][Self::finish]
/// once after the benchmark loop.
pub struct TpZcrWith2Thread {
    req_tx: Producer<'static>,
    resp_rx: Consumer<'static>,
    worker: Option<thread::JoinHandle<(TProbe, TProbe)>>,
    send_probe: TProbe,
    recv_probe: TProbe,
    counter: u64,
}

impl TpZcrWith2Thread {
    /// Spawn the spinning echo worker over two fresh leaked
    /// rings, optionally pinning it to `worker_cpu`.
    pub fn new(worker_cpu: Option<usize>) -> Self {
        let (req_tx, mut req_rx) = leak_ring();
        let (mut resp_tx, resp_rx) = leak_ring();
        let worker = thread::spawn(move || {
            pin::pin_current(worker_cpu);
            let mut recv_probe = TProbe::new("worker recv req (spsc reserve+release)");
            let mut send_probe = TProbe::new("worker send resp (spsc reserve+commit)");
            loop {
                let s = ticks::read_ticks();
                let v = {
                    let slot = req_rx
                        .reserve_slot_with::<Msg>(|_| {
                            core::hint::spin_loop();
                            true
                        })
                        .expect("spin closure never gives up");
                    let v = *slot;
                    slot.release();
                    v
                };
                recv_probe.record(ticks::read_ticks().wrapping_sub(s));
                if v == STOP {
                    break;
                }
                let s = ticks::read_ticks();
                let mut slot = resp_tx
                    .reserve_slot_with::<Msg>(|_| {
                        core::hint::spin_loop();
                        true
                    })
                    .expect("spin closure never gives up");
                *slot = v;
                slot.commit();
                send_probe.record(ticks::read_ticks().wrapping_sub(s));
            }
            (recv_probe, send_probe)
        });
        Self {
            req_tx,
            resp_rx,
            worker: Some(worker),
            send_probe: TProbe::new("main send req (spsc reserve+commit)"),
            recv_probe: TProbe::new("main recv resp (spsc reserve+release)"),
            counter: 0,
        }
    }

    /// Shut down the worker and return the four probes in report
    /// order: main send, main recv, worker recv, worker send.
    /// Must be called exactly once, after the benchmark loop.
    pub fn finish(&mut self) -> (TProbe, TProbe, TProbe, TProbe) {
        let mut slot = self
            .req_tx
            .reserve_slot_with::<Msg>(|_| {
                core::hint::spin_loop();
                true
            })
            .expect("spin closure never gives up");
        *slot = STOP;
        slot.commit();
        let (worker_recv, worker_send) = self
            .worker
            .take()
            .expect("finish called twice")
            .join()
            .expect("worker panicked");
        let send = std::mem::replace(&mut self.send_probe, TProbe::new(""));
        let recv = std::mem::replace(&mut self.recv_probe, TProbe::new(""));
        (send, recv, worker_recv, worker_send)
    }
}

impl Bench for TpZcrWith2Thread {
    fn name(&self) -> &str {
        "tp-zcr-with-2t: zc-ring-x1 reserve_slot_with round-trip (2 threads, spin, TProbe phases)"
    }

    fn step(&mut self) -> u64 {
        self.counter = self.counter.wrapping_add(1);
        if self.counter == STOP {
            self.counter = 1;
        }
        let s = ticks::read_ticks();
        let mut slot = self
            .req_tx
            .reserve_slot_with::<Msg>(|_| {
                core::hint::spin_loop();
                true
            })
            .expect("spin closure never gives up");
        *slot = self.counter;
        slot.commit();
        self.send_probe.record(ticks::read_ticks().wrapping_sub(s));
        let s = ticks::read_ticks();
        let slot = self
            .resp_rx
            .reserve_slot_with::<Msg>(|_| {
                core::hint::spin_loop();
                true
            })
            .expect("spin closure never gives up");
        let v = *slot;
        slot.release();
        self.recv_probe.record(ticks::read_ticks().wrapping_sub(s));
        black_box(v)
    }
}

impl Drop for TpZcrWith2Thread {
    /// Panic-path safety net: if run() didn't reach finish(),
    /// tear down the worker the same way zcr_with_2t does.
    fn drop(&mut self) {
        if self.worker.is_none() {
            return;
        }
        let mut slot = self
            .req_tx
            .reserve_slot_with::<Msg>(|_| {
                core::hint::spin_loop();
                true
            })
            .expect("spin closure never gives up");
        *slot = STOP;
        slot.commit();
        if let Some(worker) = self.worker.take() {
            let _ = worker.join();
        }
    }
}

/// Registry entry point.
pub fn run(cfg: &RunCfg) {
    let mut bench = TpZcrWith2Thread::new(cfg.core_for(1));
    let (hist, outer, inner, duration_s, suspended_s) = harness::run_adaptive(&mut bench, cfg);
    let (main_send, main_recv, worker_recv, worker_send) = bench.finish();
    harness::print_report(
        bench.name(),
        outer,
        inner,
        duration_s,
        &hist,
        cfg,
        suspended_s,
    );
    main_send.report(cfg.report_ticks);
    main_recv.report(cfg.report_ticks);
    worker_recv.report(cfg.report_ticks);
    worker_send.report(cfg.report_ticks);
}

