1	//! AArch64 impl of the tick-counter abstraction: the Generic
2	//! Timer's virtual count (`CNTVCT_EL0`) for reads and its
3	//! self-reported frequency (`CNTFRQ_EL0`) for the conversion
4	//! ratio. Unlike x86, no calibration loop and no feature probe
5	//! are needed: the Generic Timer is a mandatory architectural
6	//! feature, invariant by spec (fixed frequency, keeps counting
7	//! across idle/power states), and its frequency is readable
8	//! directly from a register.
9	
10	use std::sync::OnceLock;
11	
12	#[inline(always)]
13	pub fn read_ticks() -> u64 {
14	    // Plain `mrs` without an `isb` barrier, matching the plain
15	    // (unfenced) `rdtsc` in the x86_64 impl. The read can be
16	    // speculated a few instructions early/late, but at Generic
17	    // Timer rates (54 MHz on the BCM2712 — ~18.5 ns per tick)
18	    // that blur is well under one tick.
19	    let ticks: u64;
20	    unsafe {
21	        core::arch::asm!(
22	            "mrs {t}, cntvct_el0",
23	            t = out(reg) ticks,
24	            options(nomem, nostack, preserves_flags),
25	        );
26	    }
27	    ticks
28	}
29	
30	static TICKS_PER_NS: OnceLock<f64> = OnceLock::new();
31	
32	pub fn ticks_per_ns() -> f64 {
33	    *TICKS_PER_NS.get_or_init(|| cntfrq_hz() as f64 / 1e9)
34	}
35	
36	/// `CNTFRQ_EL0` — Generic Timer frequency in Hz, programmed by
37	/// firmware at boot (54 MHz on the BCM2712 / Raspberry Pi 5).
38	/// The register is architecturally 32-bit; `mrs` into a 64-bit
39	/// register zero-extends.
40	fn cntfrq_hz() -> u64 {
41	    let hz: u64;
42	    unsafe {
43	        core::arch::asm!(
44	            "mrs {f}, cntfrq_el0",
45	            f = out(reg) hz,
46	            options(nomem, nostack, preserves_flags),
47	        );
48	    }
49	    hz
50	}
51	
52	pub fn require_ok() {
53	    // The counter itself needs no invariance probe (see module
54	    // doc). The one historical failure mode is firmware leaving
55	    // CNTFRQ_EL0 unprogrammed (zero), which would make every
56	    // tick-to-ns conversion divide by zero downstream.
57	    if cntfrq_hz() == 0 {
58	        eprintln!(
59	            "error: CNTFRQ_EL0 reads 0 — firmware did not program \
60	             the Generic Timer frequency, so tick counts can't be \
61	             converted to nanoseconds; refusing to run."
62	        );
63	        std::process::exit(1);
64	    }
65	}
