    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn start_end_appends_one_record() {
        let mut p = TProbe2::new("t");
        let id = p.start(42);
        p.end(id);
        assert_eq!(p.records.len(), 1);
