59	/// between threads (e.g. returned via a `JoinHandle<TProbeSpan>`
60	/// on shutdown).
61	pub struct TProbeSpan {
62	    name: String,
63	    hist: Histogram<u64>,
64	    records: Vec<Record>,
65	}
66	
67	impl TProbeSpan {
68	    /// Create an empty probe. Histogram upper bound is 1e12
69	    /// ticks (~250 s at 4 GHz, ~100 s at 10 GHz), 3 significant
70	    /// figures.
71	    ///
72	    /// Exits the process (code 1) if the hardware tick counter
73	    /// isn't usable — see [`crate::ticks::require_ok`].
74	    pub fn new(name: &str) -> Self {
75	        ticks::require_ok();
76	        let _ = ticks::ticks_per_ns();
77	        Self {
78	            name: name.to_string(),
79	            hist: Histogram::<u64>::new_with_bounds(1, 1_000_000_000_000, 3).unwrap(), // OK: constant bounds are valid
80	            records: Vec::new(),
81	        }
82	    }
83	
84	    /// Begin a span. Reads the hardware tick counter and
85	    /// returns an opaque [`TProbeSpanId`] carrying `(site_id,
86	    /// start_tsc)`. The id must eventually be passed to
87	    /// [`TProbeSpan::end`]; a dropped id leaves no record.
88	    #[inline]
89	    pub fn start(&mut self, site_id: u64) -> TProbeSpanId {
90	        TProbeSpanId {
91	            site_id,
92	            start_tsc: ticks::read_ticks(),
93	        }
94	    }
95	
96	    /// End the span started by [`TProbeSpan::start`]. Reads the
97	    /// hardware tick counter and appends a complete record
98	    /// `(site_id, start_tsc, end_tsc)` to the probe's record
99	    /// buffer. Delta and histogram ingestion are deferred to
100	    /// [`TProbeSpan::report`].
101	    #[inline]
102	    pub fn end(&mut self, tpri: TProbeSpanId) {
103	        let end_tsc = ticks::read_ticks();
104	        self.records.push(Record {
105	            site_id: tpri.site_id,
106	            start_tsc: tpri.start_tsc,
107	            end_tsc,
108	        });
109	    }
110	
111	    /// Render a band-table report for this probe. `as_ticks`
112	    /// controls the display unit: `false` converts stored tick
113	    /// deltas to nanoseconds (default for the CLI); `true` shows
114	    /// raw ticks (`-t`/`--ticks`).
115	    ///
116	    /// Drains any pending `start`/`end` records into the histogram
117	    /// before rendering: `delta = end_tsc − start_tsc`, clamped to
118	    /// `1` since the histogram lower bound is 1.
119	    pub fn report(&mut self, as_ticks: bool) {
120	        for r in self.records.drain(..) {
121	            let delta = r.end_tsc.saturating_sub(r.start_tsc);
122	            self.hist.record(delta.max(1)).unwrap(); // OK: clamped ≥1, and any real delta is under the 1e12 bound
123	        }
124	        band_table::render("tprobe-span", &self.name, &self.hist, as_ticks);
125	    }
126	}
127	
128	#[cfg(test)]
129	mod tests {
130	    use super::*;
131	
132	    #[test]
133	    fn start_end_appends_one_record() {
134	        let mut p = TProbeSpan::new("t");
135	        let id = p.start(42);
136	        p.end(id);
137	        assert_eq!(p.records.len(), 1);
138	        let r = &p.records[0];
139	        assert_eq!(r.site_id, 42);
140	        assert!(r.end_tsc >= r.start_tsc);
141	    }
142	
143	    #[test]
144	    fn start_end_preserves_start_tsc() {
145	        let mut p = TProbeSpan::new("t");
146	        let id = p.start(7);
147	        let saved_start = id.start_tsc;
148	        p.end(id);
149	        let r = &p.records[0];
150	        assert_eq!(r.site_id, 7);
151	        assert_eq!(r.start_tsc, saved_start);
152	    }
153	
154	    #[test]
155	    fn start_end_interleaved_non_stack() {
156	        let mut p = TProbeSpan::new("t");
157	        let a = p.start(1);
158	        let b = p.start(2);
159	        p.end(a);
160	        p.end(b);
161	        assert_eq!(p.records.len(), 2);
162	        assert_eq!(p.records[0].site_id, 1);
163	        assert_eq!(p.records[1].site_id, 2);
164	    }
165	
166	    #[test]
167	    fn report_drains_records_into_histogram() {
168	        let mut p = TProbeSpan::new("t");
169	        let id1 = p.start(1);
170	        p.end(id1);
171	        let id2 = p.start(2);
172	        p.end(id2);
173	        assert_eq!(p.hist.len(), 0);
174	        assert_eq!(p.records.len(), 2);
175	
176	        p.report(false);
177	        assert_eq!(p.records.len(), 0);
178	        assert_eq!(p.hist.len(), 2);
179	
180	        // Idempotent: a second report drains nothing, hist unchanged.
181	        p.report(false);
182	        assert_eq!(p.hist.len(), 2);
183	    }
184	}

