1	//! Demo binary: both primitives working across threads,
2	//! with throughput printed — run `cargo run --release`, or
3	//! `cargo install --path . --locked` and run
4	//! `zc-ring-x1-demo`. `-V`/`--version` prints the
5	//! version-of-record so you know exactly which build you
6	//! are testing.
7	//!
8	//! - Part 1, the ring: an SPSC pair moves typed messages
9	//!   in place (reserve → write → commit; reserve → read →
10	//!   release) — first both ends on one thread
11	//!   (the ring's own cost), then one producer thread to
12	//!   one consumer thread: unpinned, pinned to two different
13	//!   physical cores, and pinned to one physical core's two
14	//!   SMT siblings (shared L1/L2, when the CPU has SMT).
15	//!   The MPSC sibling runs beside it at each placement
16	//!   (send_with closure fill), plus a 2-producer + 1-consumer
17	//!   line — the shape only the MPSC ring can run.
18	//! - Part 2, the pool: an allocator thread allocs and
19	//!   fills `BufSlot`s and hands them to a freer thread —
20	//!   "send" today is moving the guard (see the README's
21	//!   usage model); getting a buffer implies nothing about
22	//!   when it is sent or freed.
23	//! - The composed form — descriptors through the ring,
24	//!   payloads at rest in pool buffers — runs between them:
25	//!   alloc → into_desc → ring → resolve → free, with the
26	//!   same placement ladder as the raw ring.
27	
28	use std::time::Instant;
29	
30	use zc_ring_x1::{
31	    BufSlot, CACHE_LINE_SIZE, Desc, Empty, Exhausted, Full, MpscRing, Pool, PoolRegistry, Ring,
32	    policy,
33	};
34	use zerocopy::{FromBytes, Immutable, IntoBytes, KnownLayout};
35	
36	/// Messages moved per part.
37	const COUNT: u64 = 1_000_000;
38	
39	/// Ring slots / pool buffers (small on purpose: recycling
40	/// under pressure is the interesting case).
41	const DEPTH: u32 = 64;
42	
43	/// The demo message: the sequence number the consumer
44	/// asserts, and `val` — spare payload, doubling as the
45	/// producer id in the multi-producer line.
46	#[derive(FromBytes, IntoBytes, KnownLayout, Immutable, Debug, PartialEq)]
47	#[repr(C)]
48	struct Msg {
49	    seq: u64,
50	    val: u64,
51	}
52	
53	/// Region for either primitive: biggest header (ring, 4
54	/// lines) + DEPTH one-line slots/buffers.
55	#[repr(C, align(64))]
56	struct Region([u8; 4 * CACHE_LINE_SIZE + DEPTH as usize * CACHE_LINE_SIZE]);
57	
58	/// Region for the MPSC ring: header + per-slot seq array
59	/// (DEPTH × 4 B, padded to a line) + DEPTH one-line slots.
60	#[repr(C, align(64))]
61	struct MpscRegion(
62	    [u8; 4 * CACHE_LINE_SIZE
63	        + (DEPTH as usize * 4).next_multiple_of(CACHE_LINE_SIZE)
64	        + DEPTH as usize * CACHE_LINE_SIZE],
65	);
66	
67	/// Group a count into comma-separated thousands
68	/// (`1234567` → `"1,234,567"`).
69	fn commas(n: u64) -> String {
70	    let digits = n.to_string();
71	    let mut out = String::with_capacity(digits.len() + digits.len() / 3);
72	    for (i, c) in digits.chars().enumerate() {
73	        if i > 0 && (digits.len() - i).is_multiple_of(3) {
74	            out.push(',');
75	        }
76	        out.push(c);
77	    }
78	    out
79	}
80	
81	/// Print one part's line: msgs/sec (comma-grouped) and
82	/// ns/msg from the part's elapsed seconds.
83	fn report(label: &str, secs: f64) {
84	    let rate = commas((COUNT as f64 / secs) as u64);
85	    let ns_per_msg = secs * 1e9 / COUNT as f64;
86	    println!("{label:<46} {rate:>12} msgs/sec  {ns_per_msg:>7.1} ns/msg");
87	}
88	
89	/// Parse a /sys cpu-list string ("0,12" or "0-2,6") into cpu
90	/// numbers; malformed pieces are skipped.
91	#[cfg(target_os = "linux")]
92	fn parse_cpu_list(s: &str) -> Vec<usize> {
93	    let mut out = Vec::new();
94	    for part in s.trim().split(',') {
95	        match part.split_once('-') {
96	            Some((lo, hi)) => {
97	                if let (Ok(lo), Ok(hi)) = (lo.parse::<usize>(), hi.parse::<usize>()) {
98	                    out.extend(lo..=hi);
99	                }
100	            }
101	            None => {
102	                if let Ok(n) = part.parse() {
103	                    out.push(n);
104	                }
105	            }
106	        }
107	    }
108	    out
109	}
110	
111	/// A `(producer cpu, consumer cpu)` pin for a 2t run;
112	/// `None` means the pair is unavailable / leave unpinned.
113	type PinPair = Option<(usize, usize)>;
114	
115	/// Discover two cpu pairs for the pinned 2t runs from
116	/// /sys/devices/system/cpu; `None` when the machine lacks the
117	/// shape (or not Linux).
118	///
119	/// - `.0` — same physical core: cpu0 and its SMT sibling
120	///   (shared L1/L2, the cheapest handoff).
121	/// - `.1` — different physical cores: cpu0 and a core outside
122	///   cpu0's L3 group when one exists (the farthest handoff),
123	///   else any non-sibling core.
124	#[cfg(target_os = "linux")]
125	fn discover_pin_pairs() -> (PinPair, PinPair) {
126	    let read = |path: &str| std::fs::read_to_string(path).ok();
127	    let siblings = read("/sys/devices/system/cpu/cpu0/topology/thread_siblings_list")
128	        .map(|s| parse_cpu_list(&s))
129	        .unwrap_or_default();
130	    let smt = (siblings.len() >= 2).then(|| (siblings[0], siblings[1]));
131	    let online = read("/sys/devices/system/cpu/online")
132	        .map(|s| parse_cpu_list(&s))
133	        .unwrap_or_default();
134	    let l3 = read("/sys/devices/system/cpu/cpu0/cache/index3/shared_cpu_list")
135	        .map(|s| parse_cpu_list(&s))
136	        .unwrap_or_else(|| siblings.clone());
137	    let far = online
138	        .iter()
139	        .copied()
140	        .find(|c| !l3.contains(c))
141	        .or_else(|| {
142	            online
143	                .iter()
144	                .copied()
145	                .find(|c| *c != 0 && !siblings.contains(c))
146	        });
147	    (smt, far.map(|c| (0, c)))
148	}
149	
150	/// Non-Linux stub: no pinned runs.
151	#[cfg(not(target_os = "linux"))]
152	fn discover_pin_pairs() -> (PinPair, PinPair) {
153	    (None, None)
154	}
155	
156	/// Pin the calling thread to `cpu` via sched_setaffinity;
157	/// panics on failure (a demo run with a silently ignored pin
158	/// would report a mislabeled number).
159	#[cfg(target_os = "linux")]
160	fn pin_to_cpu(cpu: usize) {
161	    // SAFETY: cpu_set_t is a plain bitmask; CPU_ZERO/CPU_SET
162	    // initialize it fully before sched_setaffinity reads it.
163	    unsafe {
164	        let mut set: libc::cpu_set_t = std::mem::zeroed();
165	        libc::CPU_ZERO(&mut set);
166	        libc::CPU_SET(cpu, &mut set);
167	        let rc = libc::sched_setaffinity(0, size_of::<libc::cpu_set_t>(), &set);
168	        assert_eq!(rc, 0, "sched_setaffinity({cpu}) failed");
169	    }
170	}
171	
172	/// Non-Linux stub: pinning is a no-op, so only the 1t runs
173	/// reach it (discover_pin_pairs returns no pairs); present
174	/// so the demo compiles everywhere.
175	#[cfg(not(target_os = "linux"))]
176	fn pin_to_cpu(_cpu: usize) {}
177	
178	/// Move COUNT messages single thread through the ring,
179	/// pinned to cpu 0 for consistency with the pinned 2t runs;
180	/// return elapsed seconds.
181	///
182	/// The loop runs in a scoped thread rather than pinning the
183	/// main thread: spawned threads inherit the main thread's
184	/// affinity mask, which would squeeze every later part onto
185	/// cpu 0.
186	fn spsc_ring_one_msg_1t() -> f64 {
187	    let mut region = Region([0; size_of::<Region>()]);
188	    let (mut producer, mut consumer) = Ring::init(&mut region.0, CACHE_LINE_SIZE as u32, DEPTH)
189	        .unwrap() // OK: Region is sized/aligned for the ring header + DEPTH slots
190	        .split();
191	
192	    let start = Instant::now();
193	    std::thread::scope(|s| {
194	        s.spawn(move || {
195	            pin_to_cpu(0);
196	            for i in 0..COUNT {
197	                match producer.reserve_slot_with::<Msg>(|_| false) {
198	                    Ok(mut slot) => {
199	                        slot.seq = i;
200	                        slot.commit();
201	                    }
202	                    Err(Full) => {
203	                        panic!("spsc_ring_one_msg_1t: producer Full SHOULD NOT HAPPEN");
204	                    }
205	                }
206	                match consumer.reserve_slot_with::<Msg>(|_| false) {
207	                    Ok(msg) => {
208	                        assert_eq!(msg.seq, i);
209	                        msg.release();
210	                    }
211	                    Err(Empty) => {
212	                        panic!("spsc_ring_one_msg_1t: consumer Empty SHOULD NOT HAPPEN");
213	                    }
214	                }
215	            }
216	        });
217	    });
218	    start.elapsed().as_secs_f64()
219	}
220	
221	/// Move COUNT messages producer-thread → consumer-thread
222	/// through the ring; return elapsed seconds.
223	///
