1	//! Phase-probed 1p/1c round trip: localize where the SPSC vs
2	//! MPSC cross-thread latency gap lives.
3	//!
4	//! Main sends a counter to a worker over one ring and waits for
5	//! the echo on a second ring; each of the four protocol phases
6	//! is measured by its own [`TProbe`] (two `read_ticks` bracket
7	//! the endpoint call), so the reports separate the sides of the
8	//! handoff:
9	//!
10	//! - `main send` / `worker send` — the producer's reserve +
11	//!   fill + commit, including any stall acquiring peer-written
12	//!   cache lines. The ring is never full here (one message in
13	//!   flight, 8 slots), so no send ever waits for space.
14	//! - `worker recv` / `main recv` — the consumer's spin wait +
15	//!   read + release. These absorb the in-flight half trip;
16	//!   `worker recv` also absorbs main's inter-iteration framing
17	//!   (probe records, the every-N clock check).
18	//!
19	//! The generic machinery (CLI grammar, pinning, drive loop,
20	//! reporting) is the sibling `tp_runner` crate; this example
21	//! contributes only the two ring flavors.
22	
23	use tp_runner::{Cfg, STOP, drive, pin_to_cpu, report, spin, usage_exit};
24	use tprobe::TProbe;
25	use tprobe::ticks;
26	use zc_ring_x1::{CACHE_LINE_SIZE, MpscRing, Ring};
27	
28	/// The CLI grammar, interpreted by [`Cfg::parse`] plus this
29	/// example's flavor positionals.
30	const USAGE: &str = "tp_roundtrip [spsc|mpsc|both] [-d secs] [--pin main,worker] [-t] [--decimals n]";
31	
32	/// Ring slots per direction — a power of two, comfortably above
33	/// the one message ever in flight.
34	const DEPTH: u32 = 8;
35	
36	/// Region for one SPSC ring: 4-line header + DEPTH one-line
37	/// slots.
38	#[repr(C, align(64))]
39	struct Region([u8; 4 * CACHE_LINE_SIZE + DEPTH as usize * CACHE_LINE_SIZE]);
40	
41	/// Region for one MPSC ring: header + per-slot seq array
42	/// (DEPTH × 4 B, padded to a line) + DEPTH one-line slots.
43	#[repr(C, align(64))]
44	struct MpscRegion(
45	    [u8; 4 * CACHE_LINE_SIZE
46	        + (DEPTH as usize * 4).next_multiple_of(CACHE_LINE_SIZE)
47	        + DEPTH as usize * CACHE_LINE_SIZE],
48	);
49	
50	/// SPSC flavor: two `Ring`s, both ends `reserve_slot_with`
51	/// under the [`spin`] policy.
52	fn run_spsc(cfg: &Cfg) {
53	    let mut req_region = Region([0; size_of::<Region>()]);
54	    let mut resp_region = Region([0; size_of::<Region>()]);
55	    let (mut req_tx, mut req_rx) = Ring::init(&mut req_region.0, CACHE_LINE_SIZE as u32, DEPTH)
56	        .unwrap() // OK: Region is sized/aligned for the header + DEPTH slots
57	        .split();
58	    let (mut resp_tx, mut resp_rx) = Ring::init(&mut resp_region.0, CACHE_LINE_SIZE as u32, DEPTH)
59	        .unwrap() // OK: Region is sized/aligned for the header + DEPTH slots
60	        .split();
61	
62	    let probes = std::thread::scope(|s| {
63	        let worker_cpu = cfg.pin.map(|(_, w)| w);
64	        let worker = s.spawn(move || {
65	            if let Some(cpu) = worker_cpu {
66	                pin_to_cpu(cpu);
67	            }
68	            let mut recv_probe = TProbe::new("spsc worker recv (reserve+release)");
69	            let mut send_probe = TProbe::new("spsc worker send (reserve+commit)");
70	            loop {
