1	//! Generic runner for phase-probed measurement examples: CLI
2	//! config, thread pinning, and a fixed-duration round-trip
3	//! drive loop over injected send/recv closures.
4	//!
5	//! - [`Cfg`] / [`Cfg::parse`] — the shared CLI grammar
6	//!   (`-d`/`--duration`, `--pin main,worker`, `-t`/`--ticks`,
7	//!   `--decimals <n>`);
8	//!   anything else lands in `positionals` for the example to
9	//!   interpret ([`usage_exit`] for rejects).
10	//! - [`pin_to_cpu`] — sched_setaffinity pinning (Linux; no-op
11	//!   stub elsewhere).
12	//! - [`drive`] — the measured loop: send a counter, receive
13	//!   the echo, one [`TProbe`] per phase.
14	//! - [`report`] — flavor header + the phase reports in trip
15	//!   order.
16	//!
17	//! Deliberately not a benchmark harness: no adaptive loop
18	//! sizing, overhead calibration, or bench registry — for that
19	//! scale of machinery use iiac-perf.
20	
21	use std::time::{Duration, Instant};
22	
23	use tprobe::TProbe;
24	use tprobe::ticks;
25	
26	/// Sentinel available to callers as a shutdown message;
27	/// [`drive`]'s counter skips it so payload values never
28	/// collide with it.
29	pub const STOP: u64 = u64::MAX;
30	
31	/// Iterations between wall-clock checks in [`drive`], keeping
32	/// the per-iteration cost of `Instant::now` off the common
33	/// path.
34	const CLOCK_CHECK_EVERY: u64 = 4096;
35	
36	/// Parsed CLI configuration for a probed example run.
37	pub struct Cfg {
38	    /// Wall-clock budget per flavor.
39	    pub duration: Duration,
40	    /// `Some((main_cpu, worker_cpu))` pins both threads.
41	    pub pin: Option<(usize, usize)>,
42	    /// Report raw ticks instead of nanoseconds.
43	    pub ticks: bool,
44	    /// Fractional digits on report value columns.
45	    pub decimals: usize,
46	    /// Non-flag arguments, in order, for the caller to
47	    /// interpret (e.g. flavor names).
48	    pub positionals: Vec<String>,
49	}
50	
51	/// Print `usage` and exit 2.
52	pub fn usage_exit(usage: &str) -> ! {
53	    eprintln!("usage: {usage}");
54	    std::process::exit(2);
55	}
56	
57	impl Cfg {
58	    /// Parse the process args against the shared grammar;
59	    /// [`usage_exit`]s on a malformed flag. Defaults: 5 s,
60	    /// unpinned, ns reporting, 1 decimal.
61	    pub fn parse(usage: &str) -> Cfg {
62	        let mut cfg = Cfg {
63	            duration: Duration::from_secs(5),
64	            pin: None,
65	            ticks: false,
66	            decimals: 1,
67	            positionals: Vec::new(),
68	        };
69	        let mut args = std::env::args().skip(1);
70	        while let Some(a) = args.next() {
71	            match a.as_str() {
72	                "-d" | "--duration" => {
73	                    let secs: f64 = args
74	                        .next()
75	                        .and_then(|v| v.parse().ok())
76	                        .unwrap_or_else(|| usage_exit(usage));
77	                    cfg.duration = Duration::from_secs_f64(secs);
78	                }
79	                "--pin" => {
80	                    let v = args.next().unwrap_or_else(|| usage_exit(usage));
81	                    let (m, w) = v.split_once(',').unwrap_or_else(|| usage_exit(usage));
82	                    let m = m.parse().unwrap_or_else(|_| usage_exit(usage));
83	                    let w = w.parse().unwrap_or_else(|_| usage_exit(usage));
84	                    cfg.pin = Some((m, w));
85	                }
86	                "-t" | "--ticks" => cfg.ticks = true,
87	                "--decimals" => {
88	                    cfg.decimals = args
89	                        .next()
90	                        .and_then(|v| v.parse().ok())
91	                        .unwrap_or_else(|| usage_exit(usage));
92	                }
93	                _ if a.starts_with('-') => usage_exit(usage),
94	                _ => cfg.positionals.push(a),
95	            }
96	        }
97	        cfg
98	    }
99	}
100	
101	/// Pin the calling thread to `cpu` via sched_setaffinity;
102	/// panics on failure (a run with a silently ignored pin would
103	/// report a mislabeled number).
104	#[cfg(target_os = "linux")]
105	pub fn pin_to_cpu(cpu: usize) {
106	    // SAFETY: cpu_set_t is a plain bitmask; CPU_ZERO/CPU_SET
107	    // initialize it fully before sched_setaffinity reads it.
108	    unsafe {
109	        let mut set: libc::cpu_set_t = std::mem::zeroed();
110	        libc::CPU_ZERO(&mut set);
111	        libc::CPU_SET(cpu, &mut set);
112	        let rc = libc::sched_setaffinity(0, size_of::<libc::cpu_set_t>(), &set);
113	        assert_eq!(rc, 0, "sched_setaffinity({cpu}) failed");
114	    }
115	}
116	
117	/// Non-Linux stub: `--pin` becomes a no-op.
118	#[cfg(not(target_os = "linux"))]
119	pub fn pin_to_cpu(_cpu: usize) {}
120	
121	/// A spin wait policy: hint and keep trying. Matches the
122	/// `on_full`/`on_empty` closure shape of the ring endpoints.
123	pub fn spin(_attempt: u32) -> bool {
124	    core::hint::spin_loop();
125	    true
126	}
127	
128	/// Drive `dur` worth of round trips: send the counter via
129	/// `send`, receive the echo via `recv`; the two phases record
130	/// into `send_probe` / `recv_probe`. Returns when the budget
131	/// is spent (checked every [`CLOCK_CHECK_EVERY`] iterations).
132	/// The counter skips [`STOP`] so callers can use it as a
133	/// shutdown sentinel afterwards.
134	pub fn drive(
135	    dur: Duration,
136	    send_probe: &mut TProbe,
137	    recv_probe: &mut TProbe,
138	    mut send: impl FnMut(u64),
139	    mut recv: impl FnMut() -> u64,
140	) {
141	    let start = Instant::now();
142	    let mut counter: u64 = 0;
143	    loop {
144	        for _ in 0..CLOCK_CHECK_EVERY {
145	            counter = counter.wrapping_add(1);
146	            if counter == STOP {
147	                counter = 1;
148	            }
149	            let s = ticks::read_ticks();
150	            send(counter);
151	            send_probe.record(ticks::read_ticks().wrapping_sub(s));
152	            let s = ticks::read_ticks();
153	            let v = recv();
154	            recv_probe.record(ticks::read_ticks().wrapping_sub(s));
155	            assert_eq!(v, counter, "echo mismatch");
156	        }
157	        if start.elapsed() >= dur {
158	            return;
159	        }
160	    }
161	}
162	
163	/// Print one flavor's header, then its phase reports in the
164	/// order given (conventionally trip order: main send → worker
165	/// recv → worker send → main recv).
166	pub fn report(flavor: &str, cfg: &Cfg, probes: impl IntoIterator<Item = TProbe>) {
167	    let pin = match cfg.pin {
168	        Some((m, w)) => format!("main={m},worker={w}"),
169	        None => "none".to_string(),
170	    };
171	    println!(
172	        "{flavor} round trip [duration={:.1}s pin={pin}]:",
173	        cfg.duration.as_secs_f64(),
174	    );
175	    for p in probes {
176	        p.report(cfg.ticks, cfg.decimals);
177	    }
178	}

