/// is [`STOP`], which is passed through unrecorded.
fn instrumented_recv(probes: &mut RecvProbes, reserve: impl FnOnce(&mut u32, &mut u64) -> u64) -> u64 {
    let mut attempts: u32 = 0;
    let mut spin_start: u64 = 0;
