1	//! Shared band-table renderer for tick-valued histograms.
2	//!
3	//! Both `TProbe` (fast path, direct-histogram) and `TProbeSpan`
4	//! (scope API, records → drain) store hardware tick deltas and
5	//! want the same band-table output shape — min/p1/…/p99/max
6	//! rows with first/last/range/count/mean columns, plus summary
7	//! lines for mean, stdev, mean min-p99, stdev min-p99. This
8	//! module provides a single implementation both can call into.
9	//!
10	//! Display unit is chosen by `as_ticks`: `false` converts stored
11	//! tick values to nanoseconds via [`crate::ticks::ticks_per_ns`];
12	//! `true` shows raw ticks.
13	
14	use hdrhistogram::Histogram;
15	
16	use crate::fmt::{fmt_commas, fmt_commas_f64};
17	use crate::ticks;
18	
19	const BOUNDARY_PCTS: &[f64] = &[
20	    0.0, 0.01, 0.10, 0.20, 0.30, 0.40, 0.50, 0.60, 0.70, 0.80, 0.90, 0.99, 1.0,
21	];
22	const BOUNDARY_NAMES: &[&str] = &[
23	    "min", "p1", "p10", "p20", "p30", "p40", "p50", "p60", "p70", "p80", "p90", "p99", "max",
24	];
25	
26	/// Display unit for a rendered band table.
27	#[derive(Clone, Copy, PartialEq, Eq)]
28	pub(crate) enum Unit {
29	    /// Convert stored ticks to nanoseconds (`ns`).
30	    Ns,
31	    /// Raw stored ticks (`tk`).
32	    Ticks,
33	    /// Unitless counts (`ct`) — no conversion.
34	    Count,
35	}
36	
37	/// Render a band-table report for `hist`. `kind` is the header
38	/// label (`"tprobe"`, `"tprobe-span"`, …) and `name` is the
39	/// probe's name. `unit` picks the display unit / conversion;
40	/// `decimals` is the fractional digits on every value column.
41	pub(crate) fn render(kind: &str, name: &str, hist: &Histogram<u64>, unit: Unit, decimals: usize) {
42	    let sample_count = hist.len();
43	    println!("  {kind}: {name} [count={}]", fmt_commas(sample_count));
44	    if sample_count == 0 {
45	        println!();
46	        return;
47	    }
48	
49	    let to_ns = unit == Unit::Ns;
50	    let unit = match unit {
51	        Unit::Ns => "ns",
52	        Unit::Ticks => "tk",
53	        Unit::Count => "ct",
54	    };
55	    let tpn = ticks::ticks_per_ns();
56	    let conv = |v: u64| -> f64 { if to_ns { v as f64 / tpn } else { v as f64 } };
57	    let conv_f = |v: f64| -> f64 { if to_ns { v / tpn } else { v } };
58	
59	    let n_bands = BOUNDARY_PCTS.len() - 1;
60	    let mut band_first = vec![u64::MAX; n_bands];
61	    let mut band_last = vec![0u64; n_bands];
62	    let mut band_count = vec![0u64; n_bands];
63	    let mut band_sum = vec![0u128; n_bands];
64	
65	    let mut cumulative = 0u64;
66	    for iv in hist.iter_recorded() {
67	        let value = iv.value_iterated_to();
68	        let count = iv.count_at_value();
69	        let mid_rank = (cumulative as f64 + count as f64 / 2.0) / sample_count as f64;
70	        let idx = BOUNDARY_PCTS[1..]
71	            .iter()
72	            .position(|&b| mid_rank < b)
73	            .unwrap_or(n_bands - 1); // OK: rank ≥ last boundary → top band
74	        band_first[idx] = band_first[idx].min(value);
75	        band_last[idx] = band_last[idx].max(value);
76	        band_count[idx] += count;
77	        band_sum[idx] += value as u128 * count as u128;
78	        cumulative += count;
79	    }
80	
81	    struct BandRow {
82	        label: String,
83	        first: String,
84	        last: String,
85	        range: String,
86	        count: String,
87	        mean: String,
88	    }
89	
