        .unwrap() // OK: Region is sized/aligned for the header + DEPTH slots
        .split();
    let (mut resp_tx, mut resp_rx) = Ring::init(&mut resp_region.0, CACHE_LINE_SIZE as u32, DEPTH)
        .unwrap() // OK: Region is sized/aligned for the header + DEPTH slots
        .split();

